const observers = new Map();

export function initialize(sentinelElement, dotNetHelper) {
    if (observers.has(sentinelElement)) {
        return;
    }

    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetHelper.invokeMethodAsync("OnSentinelVisible");
            }
        }
    }, { rootMargin: "200px" });

    observer.observe(sentinelElement);
    observers.set(sentinelElement, observer);
}

export function dispose(sentinelElement) {
    const observer = observers.get(sentinelElement);
    if (observer) {
        observer.disconnect();
        observers.delete(sentinelElement);
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:80vh;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
</div>

@code {
    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether more items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when more items should be loaded.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infiniteScroll.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }

        if (module is not null && HasMore)
        {
            await module.InvokeVoidAsync("initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        await OnLoadMore.InvokeAsync();
        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose", sentinelRef);
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone during prerendering teardown.
            }
        }

        dotNetRef?.Dispose();
    }
}

